const Header = () =>  {
    return ( 
        <header>
            <menu>
                <ul>
                    <li>HTMl</li>
                    <li>CSS</li>
                    <li>JS</li>
                    <li>React</li>
                </ul>
            </menu>
        </header>
        );
}
 
export default Header;
